SELECT COUNT(*) 
FROM components 
WHERE supplier_id = (SELECT supplier_id FROM suppliers WHERE supplier_name = 'Texas Instruments');

SELECT AVG(c.pin_count) AS average_pins_per_version
FROM components c
JOIN component_versions cv ON c.component_id = cv.component_id;

SELECT AVG(reel_diameter) AS avg_reel_diameter, unit_of_measure
FROM physical_dimensions
GROUP BY unit_of_measure;
